/**
 * pages/MilkCollection.jsx — Milk entry form + daily summary + offline sync.
 * FR-M-01: Duplicate prevention | FR-M-03: Inactive cattle block | FR-AU-06: Offline
 */
import { useState, useEffect } from 'react';
import { milkAPI, cattleAPI } from '../api/endpoints';
import toast from 'react-hot-toast';
import Badge from '../components/Badge';
import { openDB } from 'idb';

// IndexedDB setup for offline entries (FR-AU-06)
const DB_NAME  = 'dairypro_offline';
const DB_STORE = 'pending_milk';

async function getOfflineDB() {
  return openDB(DB_NAME, 1, {
    upgrade(db) { db.createObjectStore(DB_STORE, { autoIncrement: true }); }
  });
}

const gradeColor = (g) => ({ A: 'green', B: 'blue', C: 'yellow', Rejected: 'red' }[g] || 'gray');

export default function MilkCollection() {
  const [cattle, setCattle]           = useState([]);
  const [summary, setSummary]         = useState(null);
  const [collections, setCollections] = useState([]);
  const [cattleSummary, setCattleSummary]   = useState([]);
  const [grandTotal, setGrandTotal]         = useState(0);
  const [monthlyData, setMonthlyData]       = useState({ months: [], cattle: [] });
  const [form, setForm]           = useState({
    cattle_id: '', shift: 'Morning', quantity_litres: '',
    fat_percentage: '', snf_percentage: '', notes: ''
  });
  const [errors, setErrors]       = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [isOnline, setIsOnline]   = useState(navigator.onLine);
  const [pendingCount, setPendingCount] = useState(0);
  const today = new Date().toISOString().slice(0, 10);
  const [selectedDate, setSelectedDate] = useState(today);

  // Inline-edit state for daily entries table
  const [editingId, setEditingId]   = useState(null);
  const [editVals, setEditVals]     = useState({ quantity_litres: '', fat_percentage: '', snf_percentage: '' });
  const [savingEdit, setSavingEdit] = useState(false);

  // Modal state for cattle-level editing (summary + monthly tables)
  const [editModal, setEditModal] = useState({
    open: false, cattleId: null, cattleName: '', monthFilter: null,
    entries: [], loadingEntries: false, editingId: null,
    editVals: { quantity_litres: '', fat_percentage: '', snf_percentage: '' }, saving: false,
  });

  useEffect(() => {
    cattleAPI.list({ is_active: true }).then(r => setCattle(r.data?.results || r.data.data?.results || []));
    milkAPI.dailySummary(selectedDate).then(r => setSummary(r.data.data)).catch(() => {});
    milkAPI.list({ collection_date: selectedDate }).then(r => setCollections(r.data?.results || r.data.data?.results || []));
    milkAPI.cattleSummary().then(r => {
      const d = r.data.data;
      setCattleSummary(d.cattle_summary || []);
      setGrandTotal(d.grand_total || 0);
    }).catch(() => {});
    milkAPI.monthlySummary().then(r => setMonthlyData(r.data.data)).catch(() => {});

    const onOnline  = () => { setIsOnline(true); handleSync(); };
    const onOffline = () => setIsOnline(false);
    window.addEventListener('online', onOnline);
    window.addEventListener('offline', onOffline);
    checkPending();
    return () => { window.removeEventListener('online', onOnline); window.removeEventListener('offline', onOffline); };
  }, [selectedDate]);

  async function checkPending() {
    const db = await getOfflineDB();
    const count = await db.count(DB_STORE);
    setPendingCount(count);
  }

  // Refresh all data after any edit
  function refreshAll() {
    milkAPI.dailySummary(selectedDate).then(r => setSummary(r.data.data)).catch(() => {});
    milkAPI.list({ collection_date: selectedDate }).then(r => setCollections(r.data?.results || r.data.data?.results || []));
    milkAPI.cattleSummary().then(r => {
      const d = r.data.data;
      setCattleSummary(d.cattle_summary || []);
      setGrandTotal(d.grand_total || 0);
    }).catch(() => {});
    milkAPI.monthlySummary().then(r => setMonthlyData(r.data.data)).catch(() => {});
  }

  // ── Inline edit for daily entries table ──────────────────────────────────────
  function startEdit(mc) {
    setEditingId(mc.id);
    setEditVals({
      quantity_litres: mc.quantity_litres,
      fat_percentage:  mc.fat_percentage  || '',
      snf_percentage:  mc.snf_percentage  || '',
    });
  }

  async function saveEdit(id) {
    setSavingEdit(true);
    try {
      await milkAPI.update(id, {
        quantity_litres: +editVals.quantity_litres,
        fat_percentage:  editVals.fat_percentage  !== '' ? +editVals.fat_percentage  : null,
        snf_percentage:  editVals.snf_percentage  !== '' ? +editVals.snf_percentage  : null,
      });
      toast.success('Entry updated!');
      setEditingId(null);
      refreshAll();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Update failed.');
    } finally {
      setSavingEdit(false);
    }
  }

  // ── Modal edit for cattle summary / monthly tables ────────────────────────────
  async function openEditModal(cattleId, cattleName, monthFilter) {
    setEditModal(m => ({ ...m, open: true, cattleId, cattleName, monthFilter, entries: [], loadingEntries: true, editingId: null }));
    try {
      const res = await milkAPI.list({ cattle: cattleId });
      let entries = res.data?.results || res.data.data?.results || [];
      if (monthFilter) {
        // monthFilter is like "Jun 2025" — keep entries whose collection_date matches
        entries = entries.filter(e => {
          const d = new Date(e.collection_date);
          const label = d.toLocaleString('en-US', { month: 'short', year: 'numeric' });
          return label === monthFilter;
        });
      }
      entries.sort((a, b) => (a.collection_date > b.collection_date ? -1 : 1));
      setEditModal(m => ({ ...m, entries, loadingEntries: false }));
    } catch {
      setEditModal(m => ({ ...m, loadingEntries: false }));
    }
  }

  function startModalEdit(mc) {
    setEditModal(m => ({
      ...m, editingId: mc.id,
      editVals: {
        quantity_litres: mc.quantity_litres,
        fat_percentage:  mc.fat_percentage  || '',
        snf_percentage:  mc.snf_percentage  || '',
      }
    }));
  }

  async function saveModalEdit(id) {
    setEditModal(m => ({ ...m, saving: true }));
    try {
      await milkAPI.update(id, {
        quantity_litres: +editModal.editVals.quantity_litres,
        fat_percentage:  editModal.editVals.fat_percentage !== '' ? +editModal.editVals.fat_percentage : null,
        snf_percentage:  editModal.editVals.snf_percentage !== '' ? +editModal.editVals.snf_percentage : null,
      });
      toast.success('Entry updated!');
      // Update the entry in modal list
      setEditModal(m => ({
        ...m, saving: false, editingId: null,
        entries: m.entries.map(e => e.id === id
          ? { ...e,
              quantity_litres: +m.editVals.quantity_litres,
              fat_percentage:  m.editVals.fat_percentage !== '' ? +m.editVals.fat_percentage : null,
              snf_percentage:  m.editVals.snf_percentage !== '' ? +m.editVals.snf_percentage : null,
            }
          : e)
      }));
      refreshAll();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Update failed.');
      setEditModal(m => ({ ...m, saving: false }));
    }
  }

  async function handleSync() {
    const db      = await getOfflineDB();
    const keys    = await db.getAllKeys(DB_STORE);
    const entries = await db.getAll(DB_STORE);
    if (!entries.length) return;
    try {
      await milkAPI.syncOffline({ entries });
      for (const key of keys) await db.delete(DB_STORE, key);
      setPendingCount(0);
      toast.success(`${entries.length} offline entries synced!`);
    } catch (e) {
      toast.error('Sync failed. Will retry when online.');
    }
  }

  const validate = () => {
    const e = {};
    if (!form.cattle_id) e.cattle_id = 'Select a cattle.';
    if (!form.quantity_litres || isNaN(form.quantity_litres) || +form.quantity_litres <= 0)
      e.quantity_litres = 'Enter a valid quantity (> 0).';
    if (form.fat_percentage && (+form.fat_percentage < 0 || +form.fat_percentage > 10))
      e.fat_percentage = 'Fat% must be between 0 and 10.';
    setErrors(e);
    return !Object.keys(e).length;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    setSubmitting(true);

    const payload = {
      cattle: form.cattle_id,
      collection_date: today,
      shift: form.shift,
      quantity_litres: +form.quantity_litres,
      fat_percentage: form.fat_percentage || null,
      snf_percentage: form.snf_percentage || null,
      notes: form.notes,
    };

    if (!isOnline) {
      // Store offline
      const db = await getOfflineDB();
      await db.add(DB_STORE, payload);
      setPendingCount(c => c + 1);
      toast('Entry saved offline. Will sync when connected.', { icon: '📶' });
      setForm(f => ({ ...f, quantity_litres: '', fat_percentage: '', snf_percentage: '', notes: '' }));
      setSubmitting(false);
      return;
    }

    try {
      await milkAPI.create(payload);
      toast.success('Milk entry recorded!');
      setForm(f => ({ ...f, quantity_litres: '', fat_percentage: '', snf_percentage: '', notes: '' }));
      milkAPI.dailySummary(selectedDate).then(r => setSummary(r.data.data));
      milkAPI.list({ collection_date: selectedDate }).then(r => setCollections(r.data?.results || r.data.data?.results || []));
      milkAPI.cattleSummary().then(r => { const d = r.data.data; setCattleSummary(d.cattle_summary || []); setGrandTotal(d.grand_total || 0); }).catch(() => {});
      milkAPI.monthlySummary().then(r => setMonthlyData(r.data.data)).catch(() => {});
    } catch (err) {
      const msg = err.response?.data?.message || 'Failed to record entry.';
      toast.error(msg);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-gray-900">🥛 Milk Collection</h1>
        <div className="flex items-center gap-3">
          {!isOnline && <Badge label="Offline Mode" variant="red" />}
          {pendingCount > 0 && (
            <button onClick={handleSync}
              className="text-sm bg-yellow-100 text-yellow-800 px-3 py-1.5 rounded-lg hover:bg-yellow-200">
              Sync {pendingCount} pending
            </button>
          )}
          <div className="flex items-center gap-2">
            <label className="text-sm text-gray-600 font-medium">Date:</label>
            <input
              type="date"
              value={selectedDate}
              max={today}
              onChange={e => setSelectedDate(e.target.value)}
              className="border border-gray-300 rounded-lg px-3 py-1.5 text-sm focus:ring-2 focus:ring-primary-500"
            />
            {selectedDate !== today && (
              <button onClick={() => setSelectedDate(today)}
                className="text-xs text-primary-600 hover:underline">
                Today
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Entry form */}
        <div className="lg:col-span-1 bg-white rounded-xl border border-gray-200 shadow-sm p-6">
          <h2 className="font-semibold text-gray-800 mb-4">Record Entry — {selectedDate}</h2>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="text-sm font-medium text-gray-700">Cattle *</label>
              <select value={form.cattle_id}
                onChange={e => setForm(f => ({ ...f, cattle_id: e.target.value }))}
                className={`mt-1 w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-primary-500
                  ${errors.cattle_id ? 'border-red-400' : 'border-gray-300'}`}>
                <option value="">Select cattle…</option>
                {cattle.map(c => (
                  <option key={c.id} value={c.id}>{c.tag_number} — {c.name || 'Unnamed'}</option>
                ))}
              </select>
              {errors.cattle_id && <p className="text-red-500 text-xs mt-1">{errors.cattle_id}</p>}
            </div>

            <div>
              <label className="text-sm font-medium text-gray-700">Shift *</label>
              <select value={form.shift}
                onChange={e => setForm(f => ({ ...f, shift: e.target.value }))}
                className="mt-1 w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-primary-500">
                <option>Morning</option>
                <option>Evening</option>
              </select>
            </div>

            <div>
              <label className="text-sm font-medium text-gray-700">Quantity (Litres) *</label>
              <input type="number" step="0.01" value={form.quantity_litres}
                onChange={e => setForm(f => ({ ...f, quantity_litres: e.target.value }))}
                className={`mt-1 w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-primary-500
                  ${errors.quantity_litres ? 'border-red-400' : 'border-gray-300'}`}
                placeholder="e.g. 12.5" />
              {errors.quantity_litres && <p className="text-red-500 text-xs mt-1">{errors.quantity_litres}</p>}
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-sm font-medium text-gray-700">Fat %</label>
                <input type="number" step="0.01" value={form.fat_percentage}
                  onChange={e => setForm(f => ({ ...f, fat_percentage: e.target.value }))}
                  className={`mt-1 w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-primary-500
                    ${errors.fat_percentage ? 'border-red-400' : 'border-gray-300'}`}
                  placeholder="e.g. 4.2" />
              </div>
              <div>
                <label className="text-sm font-medium text-gray-700">SNF %</label>
                <input type="number" step="0.01" value={form.snf_percentage}
                  onChange={e => setForm(f => ({ ...f, snf_percentage: e.target.value }))}
                  className="mt-1 w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-primary-500"
                  placeholder="e.g. 8.5" />
              </div>
            </div>

            <div>
              <label className="text-sm font-medium text-gray-700">Notes</label>
              <textarea value={form.notes}
                onChange={e => setForm(f => ({ ...f, notes: e.target.value }))}
                rows={2}
                className="mt-1 w-full border border-gray-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-primary-500"
                placeholder="Optional notes…" />
            </div>

            <button type="submit" disabled={submitting}
              className="w-full bg-primary-600 hover:bg-primary-700 text-white py-2.5 rounded-lg text-sm font-medium
                         transition-colors disabled:opacity-50">
              {submitting ? 'Recording…' : (isOnline ? 'Record Entry' : 'Save Offline')}
            </button>
          </form>
        </div>

        {/* Daily summary + table */}
        <div className="lg:col-span-2 space-y-6">
          {/* Summary */}
          {summary && (
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-5">
              <h2 className="font-semibold text-gray-800 mb-4">Summary — {selectedDate}</h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="text-center p-3 bg-blue-50 rounded-lg">
                  <div className="text-xl font-bold text-blue-700">{Number(summary.total_litres).toFixed(1)} L</div>
                  <div className="text-xs text-gray-500 mt-1">Total</div>
                </div>
                <div className="text-center p-3 bg-green-50 rounded-lg">
                  <div className="text-xl font-bold text-green-700">{summary.cattle_count}</div>
                  <div className="text-xs text-gray-500 mt-1">Cattle</div>
                </div>
                <div className="text-center p-3 bg-yellow-50 rounded-lg">
                  <div className="text-xl font-bold text-yellow-700">{Number(summary.avg_fat_pct).toFixed(1)}%</div>
                  <div className="text-xs text-gray-500 mt-1">Avg Fat</div>
                </div>
                <div className="text-center p-3 bg-purple-50 rounded-lg">
                  <div className="text-xl font-bold text-purple-700">{summary.grade_breakdown?.A || 0}</div>
                  <div className="text-xs text-gray-500 mt-1">Grade A</div>
                </div>
              </div>
            </div>
          )}

          {/* Records table */}
          <div className="bg-white rounded-xl border border-gray-300 shadow-sm overflow-hidden">
            <div className="p-4 border-b-2 border-gray-300">
              <h2 className="font-semibold text-gray-800">Entries — {selectedDate}</h2>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm border-collapse">
                <thead className="bg-gray-100 text-gray-700 text-xs uppercase">
                  <tr>
                    <th className="px-4 py-3 text-left border border-gray-300">Cattle</th>
                    <th className="px-4 py-3 text-left border border-gray-300">Shift</th>
                    <th className="px-4 py-3 text-right border border-gray-300">Qty (L)</th>
                    <th className="px-4 py-3 text-right border border-gray-300">Fat%</th>
                    <th className="px-4 py-3 text-center border border-gray-300">Grade</th>
                  </tr>
                </thead>
                <tbody>
                  {collections.length === 0 ? (
                    <tr><td colSpan={5} className="px-4 py-8 text-center text-gray-400 border border-gray-300">No entries for this date</td></tr>
                  ) : collections.map((mc, idx) => (
                    <tr key={mc.id} className={idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
                      <td className="px-4 py-2.5 font-medium border border-gray-300">{mc.cattle_detail?.name || mc.cattle_detail?.tag_number || mc.cattle}</td>
                      <td className="px-4 py-2.5 text-gray-600 border border-gray-300">{mc.shift}</td>
                      <td className="px-4 py-2.5 text-right border border-gray-300">{Number(mc.quantity_litres).toFixed(2)}</td>
                      <td className="px-4 py-2.5 text-right border border-gray-300">{mc.fat_percentage || '—'}</td>
                      <td className="px-4 py-2.5 text-center border border-gray-300">
                        {mc.quality_grade ? <Badge label={mc.quality_grade} variant={gradeColor(mc.quality_grade)} /> : '—'}
                      </td>
                    </tr>
                  ))}
                  {collections.length > 0 && (() => {
                    const morningTotal = collections
                      .filter(mc => mc.shift === 'Morning')
                      .reduce((sum, mc) => sum + Number(mc.quantity_litres), 0);
                    const eveningTotal = collections
                      .filter(mc => mc.shift === 'Evening')
                      .reduce((sum, mc) => sum + Number(mc.quantity_litres), 0);
                    const fullDayTotal = morningTotal + eveningTotal;
                    return (
                      <>
                        <tr className="bg-blue-50">
                          <td className="px-4 py-2.5 font-semibold text-blue-800 border-2 border-blue-300">Total Morning</td>
                          <td className="px-4 py-2.5 text-blue-700 border-2 border-blue-300">Morning</td>
                          <td className="px-4 py-2.5 text-right font-bold text-blue-800 border-2 border-blue-300">{morningTotal.toFixed(2)}</td>
                          <td className="px-4 py-2.5 text-right text-blue-600 border-2 border-blue-300">—</td>
                          <td className="px-4 py-2.5 text-center text-blue-600 border-2 border-blue-300">—</td>
                        </tr>
                        <tr className="bg-orange-50">
                          <td className="px-4 py-2.5 font-semibold text-orange-800 border-2 border-orange-300">Total Evening</td>
                          <td className="px-4 py-2.5 text-orange-700 border-2 border-orange-300">Evening</td>
                          <td className="px-4 py-2.5 text-right font-bold text-orange-800 border-2 border-orange-300">{eveningTotal.toFixed(2)}</td>
                          <td className="px-4 py-2.5 text-right text-orange-600 border-2 border-orange-300">—</td>
                          <td className="px-4 py-2.5 text-center text-orange-600 border-2 border-orange-300">—</td>
                        </tr>
                        <tr className="bg-green-50">
                          <td className="px-4 py-2.5 font-bold text-green-900 border-2 border-green-400">Total Full Day</td>
                          <td className="px-4 py-2.5 text-green-700 border-2 border-green-400">Morning + Evening</td>
                          <td className="px-4 py-2.5 text-right font-bold text-green-900 text-base border-2 border-green-400">{fullDayTotal.toFixed(2)} L</td>
                          <td className="px-4 py-2.5 text-right text-green-600 border-2 border-green-400">—</td>
                          <td className="px-4 py-2.5 text-center text-green-600 border-2 border-green-400">—</td>
                        </tr>
                      </>
                    );
                  })()}
                </tbody>
              </table>
            </div>
          </div>

          {/* Per-Cattle All-Time Summary Table */}
          <div className="bg-white rounded-xl border border-gray-300 shadow-sm overflow-hidden">
            <div className="p-4 border-b-2 border-gray-300 flex items-center justify-between">
              <div>
                <h2 className="font-semibold text-gray-800">🐄 Total Milk per Cattle — All Time</h2>
                <p className="text-xs text-gray-400 mt-0.5">Updates automatically when new entries are added</p>
              </div>
              <span className="text-sm font-bold text-green-700 bg-green-50 px-3 py-1 rounded-full border border-green-200">
                Grand Total: {grandTotal.toFixed(2)} L
              </span>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm border-collapse">
                <thead className="bg-gray-100 text-gray-700 text-xs uppercase">
                  <tr>
                    <th className="px-4 py-3 text-left border border-gray-300">#</th>
                    <th className="px-4 py-3 text-left border border-gray-300">Cattle Name</th>
                    <th className="px-4 py-3 text-left border border-gray-300">Tag</th>
                    <th className="px-4 py-3 text-right border border-gray-300">Morning (L)</th>
                    <th className="px-4 py-3 text-right border border-gray-300">Evening (L)</th>
                    <th className="px-4 py-3 text-right border border-gray-300">Total (L)</th>
                    <th className="px-4 py-3 text-right border border-gray-300">Entries</th>
                  </tr>
                </thead>
                <tbody>
                  {cattleSummary.length === 0 ? (
                    <tr><td colSpan={7} className="px-4 py-8 text-center text-gray-400 border border-gray-300">No data yet</td></tr>
                  ) : cattleSummary.map((row, idx) => (
                    <tr key={row.cattle_id} className={idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
                      <td className="px-4 py-2.5 text-gray-400 border border-gray-300">{idx + 1}</td>
                      <td className="px-4 py-2.5 font-medium text-gray-900 border border-gray-300">{row.cattle_name || '—'}</td>
                      <td className="px-4 py-2.5 text-gray-500 text-xs border border-gray-300">{row.tag_number}</td>
                      <td className="px-4 py-2.5 text-right text-blue-700 border border-gray-300">{row.morning_litres.toFixed(2)}</td>
                      <td className="px-4 py-2.5 text-right text-orange-700 border border-gray-300">{row.evening_litres.toFixed(2)}</td>
                      <td className="px-4 py-2.5 text-right font-bold text-gray-900 border border-gray-300">{row.total_litres.toFixed(2)}</td>
                      <td className="px-4 py-2.5 text-right text-gray-500 border border-gray-300">{row.total_entries}</td>
                    </tr>
                  ))}
                  {cattleSummary.length > 0 && (
                    <tr className="bg-green-50 font-bold">
                      <td className="px-4 py-2.5 border border-gray-300"></td>
                      <td className="px-4 py-2.5 text-green-900 border border-gray-300" colSpan={2}>Grand Total</td>
                      <td className="px-4 py-2.5 text-right text-blue-800 border border-gray-300">
                        {cattleSummary.reduce((s, r) => s + r.morning_litres, 0).toFixed(2)}
                      </td>
                      <td className="px-4 py-2.5 text-right text-orange-800 border border-gray-300">
                        {cattleSummary.reduce((s, r) => s + r.evening_litres, 0).toFixed(2)}
                      </td>
                      <td className="px-4 py-2.5 text-right text-green-900 text-base border-2 border-green-400">
                        {grandTotal.toFixed(2)} L
                      </td>
                      <td className="px-4 py-2.5 text-right text-gray-700 border border-gray-300">
                        {cattleSummary.reduce((s, r) => s + r.total_entries, 0)}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          {/* Monthly Breakdown Table */}
          <div className="bg-white rounded-xl border border-gray-300 shadow-sm overflow-hidden">
            <div className="p-4 border-b-2 border-gray-300">
              <h2 className="font-semibold text-gray-800">📅 Monthly Milk Production per Cattle (Litres)</h2>
              <p className="text-xs text-gray-400 mt-0.5">June 2025 onwards — total litres collected per cow per month</p>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm border-collapse">
                <thead className="bg-gray-100 text-gray-700 text-xs uppercase">
                  <tr>
                    <th className="px-4 py-3 text-left border border-gray-300 sticky left-0 bg-gray-100 z-10 whitespace-nowrap">Cattle</th>
                    {monthlyData.months.map(m => (
                      <th key={m} className="px-3 py-3 text-right border border-gray-300 whitespace-nowrap">{m}</th>
                    ))}
                    <th className="px-4 py-3 text-right border-2 border-gray-400 bg-gray-200 whitespace-nowrap">Total</th>
                  </tr>
                </thead>
                <tbody>
                  {monthlyData.cattle.length === 0 ? (
                    <tr><td colSpan={monthlyData.months.length + 2} className="px-4 py-8 text-center text-gray-400 border border-gray-300">No data yet</td></tr>
                  ) : monthlyData.cattle.map((cow, idx) => {
                    const rowTotal = monthlyData.months.reduce((s, m) => s + (cow.months[m] || 0), 0);
                    return (
                      <tr key={cow.cattle_id} className={idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
                        <td className="px-4 py-2.5 font-medium text-gray-900 border border-gray-300 sticky left-0 whitespace-nowrap" style={{backgroundColor: idx % 2 === 0 ? '#fff' : '#f9fafb'}}>
                          {cow.cattle_name}
                        </td>
                        {monthlyData.months.map(m => (
                          <td key={m} className="px-3 py-2.5 text-right border border-gray-300 text-gray-700">
                            {cow.months[m] ? cow.months[m].toFixed(2) : <span className="text-gray-300">—</span>}
                          </td>
                        ))}
                        <td className="px-4 py-2.5 text-right font-bold text-gray-900 border-2 border-gray-400 bg-gray-100">
                          {rowTotal.toFixed(2)}
                        </td>
                      </tr>
                    );
                  })}
                  {monthlyData.cattle.length > 0 && (
                    <tr className="bg-green-50 font-bold">
                      <td className="px-4 py-2.5 text-green-900 border border-gray-300 sticky left-0 bg-green-50">Monthly Total</td>
                      {monthlyData.months.map(m => {
                        const colTotal = monthlyData.cattle.reduce((s, cow) => s + (cow.months[m] || 0), 0);
                        return (
                          <td key={m} className="px-3 py-2.5 text-right text-green-800 border border-gray-300">
                            {colTotal.toFixed(2)}
                          </td>
                        );
                      })}
                      <td className="px-4 py-2.5 text-right text-green-900 border-2 border-green-400 bg-green-100">
                        {monthlyData.cattle.reduce((s, cow) =>
                          s + monthlyData.months.reduce((ms, m) => ms + (cow.months[m] || 0), 0), 0
                        ).toFixed(2)}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
